function forEach(r,t,n,e,i){var o;for(t+=e;t<n;t+=e)if(o=i(r.slice(t-e,t),r.slice(t,t+e)))return o;return!1}function getIntersectionPoint(r,t){var[r,n]=r,[t,e]=t,i=((r[0]-t[0])*(t[1]-e[1])-(r[1]-t[1])*(t[0]-e[0]))/((r[0]-n[0])*(t[1]-e[1])-(r[1]-n[1])*(t[0]-e[0])),t=((r[0]-t[0])*(r[1]-n[1])-(r[1]-t[1])*(r[0]-n[0]))/((r[0]-n[0])*(t[1]-e[1])-(r[1]-n[1])*(t[0]-e[0]));if(0<=i&&i<=1&&0<=t&&t<=1)return[r[0]+i*(n[0]-r[0]),r[1]+i*(n[1]-r[1])]}export{forEach,getIntersectionPoint};